public static String solve(String s, long k) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c >= 'a' && c <= 'z') {
            sb.append(c);
        } else if (c == '*') {
            if (sb.length() > 0) {
                sb.setLength(sb.length() - 1);
            }
        } else if (c == '#') {
            String current = sb.toString();
            sb.append(current);
        } else if (c == '%') {
            sb.reverse();
        }
    }
    String result = sb.toString();
    if (k < 0 || k >= result.length()) {
        return ".";
    }
    return String.valueOf(result.charAt((int) k));
}
